INSERT INTO `assessment` (`AssessmentID`, `AttachmentID`, `LecturerID`, `AssessmentDate`, `AssessmentType`, `Marks`, `Remarks`, `CriteriaScores`, `Status`, `SupervisionComments`) VALUES
(1, 1, 2, '2026-06-08', 'First Assessment', 87.00, 'John shows exceptional adaptability and team integration. His logbook entries are well-organized and his coding practices are solid.', '[8,9,8,9,10,8,9,9,8,9]', 'Completed', 'Conducted dynamic video review session and verified logs. Good coding skills.'),
(2, 2, 3, '2026-06-08', 'First Assessment', 89.00, 'Mercy has a strong grasp of vulnerability scanning concepts. She was very proactive in manual pentesting tasks.', '[9,8,9,9,10,9,9,8,9,9]', 'Completed', 'Evaluated VM sandbox environment configurations. The student is alert and highly focused.'),
(3, 3, 4, '2026-06-08', 'First Assessment', 86.00, 'David shows great analytical skills. He successfully deployed the Streamlit dashboard and optimized SQL queries.', '[8,8,9,9,9,8,9,9,8,9]', 'Completed', 'Inspected backend migrations and dashboard output structure. Outstanding analytical depth.'),
(4, 4, 5, '2026-06-08', 'First Assessment', 91.00, 'Grace did an outstanding job with React navigation configurations and component building.', '[9,9,9,10,9,9,9,9,10,9]', 'Completed', 'Reviewed GitHub repository logs and CSS visual alignments. Form validations look complete.'),
(5, 5, 6, '2026-06-08', 'First Assessment', 88.00, 'Patrick is highly proficient with Cisco CLI commands. He terminates cables neatly and plans subnets with precision.', '[9,8,9,9,9,8,9,9,9,9]', 'Completed', 'Inspected network patch panels terminations. Good understanding of DHCP configurations.'),
(6, 6, 7, '2026-06-08', 'First Assessment', 85.00, 'Evans adapted quickly to our AWS environments. His Terraform templates were clean and reusable.', '[8,9,8,9,9,8,9,8,9,8]', 'Completed', 'Verified S3 policy boundaries configurations. Demonstrates nice progress.'),
(7, 7, 8, '2026-06-08', 'First Assessment', 84.00, 'Faith handles queued hardware diagnostics tickets with great diligence and user empathy.', '[8,8,8,9,9,8,9,8,8,9]', 'Completed', 'Reviewed system diagnostics tickets logs. Punctual and active in client interactions.'),
(8, 8, 9, '2026-06-08', 'First Assessment', 85.00, 'Benson has good development workflow concepts and communicates well with the team.', '[8,8,9,9,9,8,8,9,8,9]', 'Completed', 'Evaluated local API deployments and code documentation summaries.'),
(9, 9, 10, '2026-06-08', 'First Assessment', 90.00, 'Joseph shows strong diagnostic skills in analyzing network packets and tracking open port compliance.', '[9,9,9,9,10,9,9,8,9,9]', 'Completed', 'Verified Wireshark packet logs analysis capabilities. Exceptional analytical skill.'),
(10, 10, 11, '2026-06-08', 'First Assessment', 87.00, 'Sarah has strong scripting capabilities in Pandas. She delivered correlation reports on schedule.', '[8,9,8,9,10,8,9,9,8,9]', 'Completed', 'Inspected Jupyter notebooks and outliers boxplots diagrams.'),
(11, 11, 12, '2026-06-08', 'First Assessment', 86.00, 'Peter has quick adaptation of state hooks and styling methods. He built beautiful shimmer skeletons.', '[8,8,9,9,9,8,9,9,8,9]', 'Completed', 'Reviewed DOM event listener logic files. Excellent presentation.'),
