-- -------------------------------------------------------------
-- MOCK DATA POPULATION SCRIPT FOR STUDENT PLACEMENT ATTACHMENT SYSTEM
-- Designed for Faculty of Science, Dept of Computer and Information Science
-- -------------------------------------------------------------

SET FOREIGN_KEY_CHECKS = 0;

-- Drop and recreate the logbook table to align with the application model
DROP TABLE IF EXISTS `logbookentry`;
DROP TABLE IF EXISTS `logbook`;

CREATE TABLE `logbook` (
  `LogbookID` int(11) NOT NULL AUTO_INCREMENT,
  `AttachmentID` int(11) NOT NULL,
  `WeekNumber` int(11) NOT NULL,
  `StartDate` date DEFAULT NULL,
  `EndDate` date DEFAULT NULL,
  `Activities` text DEFAULT NULL,
  `Status` varchar(20) DEFAULT 'Pending',
  `EntryDate` datetime DEFAULT CURRENT_TIMESTAMP,
  `SubmittedAt` timestamp DEFAULT CURRENT_TIMESTAMP,
  `AcademicSupervisorComments` text DEFAULT NULL,
  `HostSupervisorComments` text DEFAULT NULL,
  PRIMARY KEY (`LogbookID`),
  UNIQUE KEY `unique_week` (`AttachmentID`, `WeekNumber`),
  CONSTRAINT `logbook_ibfk_1` FOREIGN KEY (`AttachmentID`) REFERENCES `attachment` (`AttachmentID`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- Align other tables with the PHP code
ALTER TABLE `attachmentapplication` ADD COLUMN IF NOT EXISTS `FinancialClearanceStatus` varchar(20) DEFAULT 'Pending';
ALTER TABLE `attachmentapplication` ADD COLUMN IF NOT EXISTS `StartDate` date DEFAULT NULL;
ALTER TABLE `attachmentapplication` ADD COLUMN IF NOT EXISTS `EndDate` date DEFAULT NULL;

ALTER TABLE `attachment` ADD COLUMN IF NOT EXISTS `ClearedAt` timestamp NULL DEFAULT NULL;

ALTER TABLE `jobapplication` ADD COLUMN IF NOT EXISTS `RejectionReason` text DEFAULT NULL;

ALTER TABLE `assessment` ADD COLUMN IF NOT EXISTS `Status` varchar(20) DEFAULT 'Completed';
ALTER TABLE `assessment` ADD COLUMN IF NOT EXISTS `SupervisionComments` text DEFAULT NULL;

-- Truncate existing data to start clean
TRUNCATE TABLE `assessment`;
TRUNCATE TABLE `supervision`;
TRUNCATE TABLE `logbook`;
TRUNCATE TABLE `finalreport`;
TRUNCATE TABLE `jobapplication`;
TRUNCATE TABLE `attachmentopportunity`;
TRUNCATE TABLE `attachment`;
TRUNCATE TABLE `attachmentapplication`;
TRUNCATE TABLE `student`;
TRUNCATE TABLE `lecturer`;
TRUNCATE TABLE `hostorganization`;
TRUNCATE TABLE `users`;

SET FOREIGN_KEY_CHECKS = 1;

